import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { ArrowLeft, User, LogOut, Mail } from "lucide-react";
import { useAuth } from "./AuthContext";

export default function Profile() {
  const navigate = useNavigate();
  const { user, logout } = useAuth();
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    graduationYear: "",
    company: "",
    position: "",
  });
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  // Initialize form data when user data is available
  useEffect(() => {
    if (user) {
      setFormData({
        name: user.name || "Jane Doe",
        email: user.email || "jane.doe@university.edu",
        graduationYear: user.graduationYear || "2020",
        company: user.company || "Tech Company",
        position: user.position || "Software Engineer",
      });
    }
  }, [user]);

  const handleLogout = () => {
    logout();
    navigate("/");
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
    setError("");
    setSuccess("");
  };

  const handleSaveProfile = async () => {
    setError("");
    setSuccess("");

    // Validation
    if (!formData.name.trim()) {
      setError("Name is required");
      return;
    }

    if (!formData.email.trim()) {
      setError("Email is required");
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError("Please enter a valid email address");
      return;
    }

    if (!formData.graduationYear.trim()) {
      setError("Graduation year is required");
      return;
    }

    if (!formData.company.trim()) {
      setError("Company is required");
      return;
    }

    if (!formData.position.trim()) {
      setError("Position is required");
      return;
    }

    try {
      // TODO: Replace with actual API call
      // const response = await updateUserProfile(formData);
      // if (response.success) {
      setSuccess("Profile updated successfully!");
      setIsEditing(false);
      // }
    } catch (err) {
      setError("Failed to update profile. Please try again.");
      console.error("Profile update error:", err);
    }
  };

  const handleCancel = () => {
    setIsEditing(false);
    setError("");
    setSuccess("");
    // Reset form to user data
    if (user) {
      setFormData({
        name: user.name || "Jane Doe",
        email: user.email || "jane.doe@university.edu",
        graduationYear: user.graduationYear || "2020",
        company: user.company || "Tech Company",
        position: user.position || "Software Engineer",
      });
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 p-4">
      {/* Header */}
      <div className="flex justify-between items-center mb-8">
        <button
          onClick={() => navigate("/dashboard")}
          className="flex items-center gap-2 text-blue-600 hover:text-blue-800 focus:outline-none focus:ring-2 focus:ring-blue-500 rounded px-2 py-1"
          aria-label="Back to dashboard"
        >
          <ArrowLeft className="w-5 h-5" />
          Back
        </button>
        <button
          onClick={handleLogout}
          className="flex items-center gap-2 bg-red-600 text-white px-4 py-2 rounded-lg hover:bg-red-700 transition focus:outline-none focus:ring-2 focus:ring-red-500"
          aria-label="Logout"
        >
          <LogOut className="w-5 h-5" />
          Logout
        </button>
      </div>

      <div className="max-w-2xl mx-auto bg-white rounded-lg shadow p-8">
        {/* Success Message */}
        {success && (
          <div className="mb-4 p-4 bg-green-50 border border-green-200 rounded-lg">
            <p className="text-green-700 text-sm font-medium">{success}</p>
          </div>
        )}

        {/* Error Message */}
        {error && (
          <div className="mb-4 p-4 bg-red-50 border border-red-200 rounded-lg">
            <p className="text-red-700 text-sm font-medium">{error}</p>
          </div>
        )}

        {/* Profile Header */}
        <div className="flex items-center gap-4 mb-8">
          <div className="w-16 h-16 bg-blue-100 rounded-full flex items-center justify-center flex-shrink-0">
            <User className="w-8 h-8 text-blue-600" />
          </div>
          <div className="min-w-0">
            <h1 className="text-3xl font-bold text-gray-900 truncate">
              {formData.name}
            </h1>
            <div className="flex items-center gap-1 text-gray-600">
              <Mail className="w-4 h-4" />
              <p className="truncate">{formData.email}</p>
            </div>
          </div>
        </div>

        {/* Profile Content */}
        {!isEditing ? (
          <>
            {/* View Mode */}
            <div className="space-y-6 mb-8">
              <div className="border-b pb-4">
                <h3 className="text-sm font-semibold text-gray-700 mb-2">
                  Graduation Year
                </h3>
                <p className="text-lg text-gray-900">
                  {formData.graduationYear}
                </p>
              </div>
              <div className="border-b pb-4">
                <h3 className="text-sm font-semibold text-gray-700 mb-2">
                  Company
                </h3>
                <p className="text-lg text-gray-900">{formData.company}</p>
              </div>
              <div>
                <h3 className="text-sm font-semibold text-gray-700 mb-2">
                  Position
                </h3>
                <p className="text-lg text-gray-900">{formData.position}</p>
              </div>
            </div>

            <button
              onClick={() => setIsEditing(true)}
              className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition font-semibold focus:outline-none focus:ring-2 focus:ring-blue-500"
            >
              Edit Profile
            </button>
          </>
        ) : (
          <>
            {/* Edit Mode */}
            <form
              className="space-y-6 mb-8"
              onSubmit={(e) => e.preventDefault()}
            >
              <div>
                <label
                  htmlFor="name"
                  className="block text-sm font-semibold text-gray-700 mb-2"
                >
                  Full Name
                </label>
                <input
                  id="name"
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  placeholder="Enter your name"
                  required
                />
              </div>

              <div>
                <label
                  htmlFor="email"
                  className="block text-sm font-semibold text-gray-700 mb-2"
                >
                  Email
                </label>
                <input
                  id="email"
                  type="email"
                  name="email"
                  value={formData.email}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  placeholder="Enter your email"
                  required
                />
              </div>

              <div>
                <label
                  htmlFor="graduationYear"
                  className="block text-sm font-semibold text-gray-700 mb-2"
                >
                  Graduation Year
                </label>
                <input
                  id="graduationYear"
                  type="number"
                  name="graduationYear"
                  value={formData.graduationYear}
                  onChange={handleInputChange}
                  min="1950"
                  max={new Date().getFullYear() + 5}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  placeholder="e.g., 2020"
                  required
                />
              </div>

              <div>
                <label
                  htmlFor="company"
                  className="block text-sm font-semibold text-gray-700 mb-2"
                >
                  Company
                </label>
                <input
                  id="company"
                  type="text"
                  name="company"
                  value={formData.company}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  placeholder="Enter your company name"
                  required
                />
              </div>

              <div>
                <label
                  htmlFor="position"
                  className="block text-sm font-semibold text-gray-700 mb-2"
                >
                  Position
                </label>
                <input
                  id="position"
                  type="text"
                  name="position"
                  value={formData.position}
                  onChange={handleInputChange}
                  className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
                  placeholder="Enter your position"
                  required
                />
              </div>
            </form>

            {/* Edit Mode Buttons */}
            <div className="flex gap-3">
              <button
                onClick={handleSaveProfile}
                className="flex-1 bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition font-semibold focus:outline-none focus:ring-2 focus:ring-blue-500"
              >
                Save Changes
              </button>
              <button
                onClick={handleCancel}
                className="flex-1 bg-gray-300 text-gray-800 py-2 rounded-lg hover:bg-gray-400 transition font-semibold focus:outline-none focus:ring-2 focus:ring-gray-500"
              >
                Cancel
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}
